sp_widget.client_script:
api.controller = function($location) {
  var c = this;
  c.currentStep = 1;
  c.totalSteps = 3;
  c.submitting = false;

  c.form = {
    space_id: $location.search().space_id || '',
    date: '',
    start_time: '',
    end_time: '',
    event_details: ''
  };

  c.getSelectedSpace = function() {
    if (!c.form.space_id || !c.data.spaces) return null;
    for (var i = 0; i < c.data.spaces.length; i++) {
      if (c.data.spaces[i].sys_id === c.form.space_id) {
        return c.data.spaces[i];
      }
    }
    return null;
  };

  c.nextStep = function() {
    if (c.currentStep < c.totalSteps) {
      c.currentStep++;
    }
  };

  c.prevStep = function() {
    if (c.currentStep > 1) {
      c.currentStep--;
    }
  };

  c.canProceed = function() {
    if (c.currentStep === 1) {
      return !!c.form.space_id;
    }
    if (c.currentStep === 2) {
      return !!(c.form.date && c.form.start_time && c.form.end_time);
    }
    return true;
  };

  c.submitReservation = function() {
    c.submitting = true;
    c.data.message = '';
    c.server.get({
      action: 'submit',
      space_id: c.form.space_id,
      date: c.form.date,
      start_time: c.form.start_time,
      end_time: c.form.end_time,
      event_details: c.form.event_details
    }).then(function(r) {
      c.data = r.data;
      c.submitting = false;
      if (r.data.success) {
        c.currentStep = 4;
      }
    });
  };

  c.goToMyRequests = function() {
    $location.search('id', 'cs_portal_my_requests');
    $location.search('space_id', null);
  };
};

sp_widget.css:
.sp-reserve-wizard {
  padding: 20px 0;
  max-width: 700px;
  margin: 0 auto;
}

.sp-wizard-title {
  text-align: center;
  color: $text-color;
  font-size: 24px;
  font-weight: 600;
  margin: 0 0 30px 0;
}

.sp-wizard-progress {
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 30px;
}

.sp-step {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}

.sp-step-number {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: $background-secondary;
  color: $text-muted;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 600;
  font-size: 14px;
  border: 2px solid $border-tertiary;
}

.sp-step-active .sp-step-number {
  background: $brand-primary;
  color: $btn-primary-color;
  border-color: $brand-primary;
}

.sp-step-complete .sp-step-number {
  background: $brand-success;
  color: $btn-primary-color;
  border-color: $brand-success;
}

.sp-step-label {
  font-size: $font-size-small;
  color: $text-muted;
}

.sp-step-active .sp-step-label {
  color: $text-color;
  font-weight: 600;
}

.sp-step-line {
  width: 60px;
  height: 2px;
  background: $border-tertiary;
  margin: 0 10px;
  margin-bottom: 20px;
}

.sp-line-active {
  background: $brand-success;
}

.sp-wizard-panel {
  border-radius: $border-radius-large;
  border: 1px solid $border-tertiary;
}

.sp-step-title {
  color: $text-color;
  font-weight: 600;
  margin: 0 0 8px 0;
}

.sp-step-desc {
  color: $text-secondary;
  margin-bottom: 20px;
}

.sp-summary-card {
  background: $background-secondary;
  border-radius: $border-radius-base;
  padding: 16px;
  margin-bottom: 16px;
}

.sp-summary-row {
  padding: 8px 0;
  border-bottom: 1px solid $border-tertiary;
  display: flex;
  gap: 12px;
}

.sp-summary-row:last-child {
  border-bottom: none;
}

.sp-summary-label {
  font-weight: 600;
  color: $text-color;
  min-width: 80px;
}

.sp-summary-value {
  color: $text-secondary;
}

.sp-wizard-nav {
  margin-top: 20px;
  display: flex;
  justify-content: space-between;
}

.sp-success-state {
  text-align: center;
  padding: 40px 20px;
}

.sp-success-icon {
  font-size: 64px;
  color: $brand-success;
  margin-bottom: 16px;
}

.sp-success-title {
  color: $text-color;
  margin: 0 0 10px 0;
}

.sp-success-msg {
  color: $text-secondary;
  margin-bottom: 8px;
}

.sp-success-number {
  color: $brand-primary;
  font-weight: 600;
  margin-bottom: 20px;
}

.sp-alert {
  padding: 12px 16px;
  border-radius: $border-radius-base;
  margin-top: 16px;
}

.sp-alert-danger {
  background: $state-danger-bg;
  color: $brand-danger;
}

sp_widget.script:
(function() {
  data.spaces = [];
  data.message = '';
  data.success = false;
  data.reservationNumber = '';

  try {
    if (input && input.action === 'submit') {
      var gr = new GlideRecord('x_2084960_commun_0_reservation');
      gr.initialize();
      gr.setValue('space', input.space_id || '');
      gr.setValue('date', input.date || '');
      gr.setValue('start_time', input.start_time || '');
      gr.setValue('end_time', input.end_time || '');
      gr.setValue('requested_by', gs.getUserID());
      gr.setValue('event_details', input.event_details || '');
      gr.setValue('status', 'pending');
      var id = gr.insert();
      if (id) {
        var created = new GlideRecord('x_2084960_commun_0_reservation');
        created.addQuery('sys_id', id);
        created.setLimit(1);
        created.query();
        if (created.next()) {
          data.reservationNumber = created.getValue('number') + '';
        }
        data.success = true;
        data.message = 'Reservation submitted successfully!';
      } else {
        data.message = 'Failed to create reservation.';
      }
      return;
    }

    // Load spaces for dropdown
    var spaceGr = new GlideRecord('x_2084960_commun_0_space');
    spaceGr.addQuery('status', 'available');
    spaceGr.orderBy('name');
    spaceGr.setLimit(100);
    spaceGr.query();
    while (spaceGr.next()) {
      data.spaces.push({
        sys_id: spaceGr.getUniqueValue(),
        name: spaceGr.getValue('name') + '',
        space_type: spaceGr.getValue('space_type') + '',
        capacity: spaceGr.getValue('capacity') + ''
      });
    }
  } catch(e) {
    gs.error('Reserve Wizard widget error: ' + e.message);
    data.message = 'An error occurred.';
  }
})();
